import json
import anthropic
from typing import Any

client = anthropic.Anthropic()

SCHEMA_REQUIRED_KEYS = {"action", "target", "confidence"}

def validated_llm_call(
    prompt: str,
    max_retries: int = 3,
    temperature: float = 0.0,
) -> dict[str, Any]:
    """Call the LLM, validate JSON output, retry with repair prompt on failure."""
    messages = [{"role": "user", "content": prompt}]

    for attempt in range(max_retries):
        response = client.messages.create(
            model="claude-3-5-haiku-20241022",
            max_tokens=512,
            temperature=temperature,
            messages=messages,
        )
        raw = response.content[0].text.strip()

        # Strip markdown code fences if present
        if raw.startswith("```"):
            raw = raw.split("\n", 1)[-1].rsplit("```", 1)[0].strip()

        try:
            parsed = json.loads(raw)
        except json.JSONDecodeError as e:
            if attempt < max_retries - 1:
                # Append the failed response and a repair instruction
                messages.append({"role": "assistant", "content": raw})
                messages.append({
                    "role": "user",
                    "content": (
                        f"That response was not valid JSON ({e}). "
                        "Please respond with valid JSON only, no prose."
                    ),
                })
                continue
            raise ValueError(f"LLM returned invalid JSON after {max_retries} attempts") from e

        missing = SCHEMA_REQUIRED_KEYS - parsed.keys()
        if missing:
            if attempt < max_retries - 1:
                messages.append({"role": "assistant", "content": raw})
                messages.append({
                    "role": "user",
                    "content": (
                        f"The JSON is missing required fields: {missing}. "
                        "Please include all required fields: action, target, confidence."
                    ),
                })
                continue
            raise ValueError(f"Schema validation failed, missing: {missing}")

        return parsed

    raise RuntimeError("Unreachable")


# Example usage
result = validated_llm_call(
    'Analyze this text and respond as JSON with keys "action", "target", '
    'and "confidence" (0.0-1.0): "Move the file to the archive folder."'
)
print(result)
# Possible output: {"action": "move", "target": "archive folder", "confidence": 0.95}

import anthropic
import json

client = anthropic.Anthropic()

# Using tool_use to enforce structured output with Anthropic
tools = [{
    "name": "classify_ticket",
    "description": "Classify a support ticket",
    "input_schema": {
        "type": "object",
        "properties": {
            "category": {
                "type": "string",
                "enum": ["billing", "technical", "returns", "account", "shipping", "other"]
            },
            "urgency": {
                "type": "string",
                "enum": ["low", "medium", "high", "critical"]
            },
            "confidence": {"type": "number", "minimum": 0.0, "maximum": 1.0}
        },
        "required": ["category", "urgency", "confidence"]
    }
}]

response = client.messages.create(
    model="claude-3-5-haiku-20241022",
    max_tokens=256,
    tools=tools,
    tool_choice={"type": "any"},  # force tool use
    messages=[{
        "role": "user",
        "content": "Ticket: 'My subscription was charged twice this month and I need it fixed NOW'"
    }]
)

# Extract structured result — guaranteed schema conformance
for block in response.content:
    if block.type == "tool_use":
        result = block.input
        print(f"Category: {result['category']}")   # billing
        print(f"Urgency:  {result['urgency']}")    # critical
        print(f"Confidence: {result['confidence']:.0%}")  # ~0.95
